 WHERE comment_id = #{commentId}

UPDATE com_comment
   SET is_deleted = TRUE,
       del_dt = NOW()
 WHERE pgm_id = #{pgmId}
   AND ref_id = #{refId}
   AND is_deleted = FALSE
